#include <cuda.h>
#include <stdlib.h>
#include <stdio.h>
#include <limits.h>
#include <math.h>
#include <string.h>
#include <stdint.h>
#include <stdbool.h>
#include <sys/time.h>

#define DEFAULT_ORDER 508
#define Version "1.5"

typedef struct record {
    int value;
} record;

typedef struct knode {
    int location;
    int indices [DEFAULT_ORDER + 1];
    int keys [DEFAULT_ORDER + 1];
    bool is_leaf;
    int num_keys;
} knode;

extern void setdevice(void);
extern void checkCUDAError(const char *msg);
extern long long get_time();

__global__ void kernel_gpu(
    record *records,
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    int *keys,
    record *ans)
{
    int bid = blockIdx.x;
    if (bid >= count) return;

    int threadsPerBlock = (1024 > order) ? order : 1024;
    int thid = threadIdx.x;

    long current_node = currKnode[bid];
    long current_offset = offset[bid];
    int key_val = keys[bid];

    for (int i = 0; i < maxheight; i++) {
        if (thid < threadsPerBlock) {
            if (key_val >= knodes[current_node].keys[thid] && key_val < knodes[current_node].keys[thid+1]) {
                if (knodes_elem > knodes[current_offset].indices[thid]) {
                    current_offset = knodes[current_offset].indices[thid];
                }
            }
        }
        if (thid == 0) {
            current_node = current_offset;
        }
    }

    if (thid < threadsPerBlock) {
        if (key_val == knodes[current_node].keys[thid]) {
            ans[bid].value = records[knodes[current_node].indices[thid]].value;
        }
    }
}

void kernel_cpu(
    int cores_arg,
    record *records,
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    int *keys,
    record *ans)
{
    long long time0;
    long long time1;
    long long time2;

    time0 = get_time();

    setdevice();

    int threadsPerBlock = (1024 > order) ? order : 1024;
    int blocks = count;

    time1 = get_time();

    record *d_records;
    knode *d_knodes;
    long *d_currKnode;
    long *d_offset;
    int *d_keys;
    record *d_ans;

    cudaMalloc(&d_records, count * sizeof(record) * 100); 
    cudaMalloc(&d_knodes, knodes_elem * sizeof(knode));
    cudaMalloc(&d_currKnode, count * sizeof(long));
    cudaMalloc(&d_offset, count * sizeof(long));
    cudaMalloc(&d_keys, count * sizeof(int));
    cudaMalloc(&d_ans, count * sizeof(record));

    cudaMemcpy(d_records, records, count * sizeof(record) * 100, cudaMemcpyHostToDevice);
    cudaMemcpy(d_knodes, knodes, knodes_elem * sizeof(knode), cudaMemcpyHostToDevice);
    cudaMemcpy(d_currKnode, currKnode, count * sizeof(long), cudaMemcpyHostToDevice);
    cudaMemcpy(d_offset, offset, count * sizeof(long), cudaMemcpyHostToDevice);
    cudaMemcpy(d_keys, keys, count * sizeof(int), cudaMemcpyHostToDevice);

    kernel_gpu<<<blocks, threadsPerBlock>>>(
        d_records,
        d_knodes,
        knodes_elem,
        order,
        maxheight,
        count,
        d_currKnode,
        d_offset,
        d_keys,
        d_ans);

    checkCUDAError("kernel launch");
    cudaDeviceSynchronize();

    cudaMemcpy(ans, d_ans, count * sizeof(record), cudaMemcpyDeviceToHost);

    cudaFree(d_records);
    cudaFree(d_knodes);
    cudaFree(d_currKnode);
    cudaFree(d_offset);
    cudaFree(d_keys);
    cudaFree(d_ans);

    time2 = get_time();

    printf("Time spent in different stages of GPU KERNEL:\n");
    printf("%15.12f s, %15.12f % : GPU: SET DEVICE\n", (float)(time1-time0)/1000000, (float)(time1-time0)/(float)(time2-time0)*100);
    printf("%15.12f s, %15.12f % : GPU: KERNEL\n", (float)(time2-time1)/1000000, (float)(time2-time1)/(float)(time2-time0)*100);

    printf("Total time:\n");
    printf("%.12f s\n", (float)(time2-time0)/1000000);
}
